#include <stdio.h>

int main() {
    int t, x, h;
    if (scanf("%d", &t) != 1) return 0;
    while (t--) {
        scanf("%d %d", &x, &h);
        if (x >= h) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

